const results = [];
for (const inputItem of $input.all()) {
  let ideas = inputItem.json.output || inputItem.json.content;
  if (typeof ideas === 'string') {
    ideas = JSON.parse(ideas);
  }
  for (const idea of ideas) {
    results.push({
      json: {
        tema: idea.tema || '',
        palabras: idea.palabras || '',
        categoria: idea.categoria || '',
        Meta_descripcion: idea.Meta_descripcion || '',
        tags: idea.tags || []
      }
    });
  }
}
return results;

// Ahora usamos los tags como strings directamente
return $input.all().map(item => ({
    json: {
      ...item.json,
      Estado: "Pendiente",
      Tags: Array.isArray(item.json.tags) ? item.json.tags.join(', ') : (item.json.tags || '')
    }
}));

const rawText = $input.item.json.content.parts[0].text;

console.log('=== RAW TEXT (primeros 500) ===');
console.log(rawText.substring(0, 500));

// Extraer todo lo que esté entre el primer { y el último }
const match = rawText.match(/\{[^]*\}/);

if (!match) {
  throw new Error('No se encontró un objeto JSON en la respuesta. Contenido: ' + rawText.substring(0, 300));
}

let jsonString = match[0];

console.log('=== JSON EXTRAÍDO (primeros 300) ===');
console.log(jsonString.substring(0, 300));

// Intentar parsear directamente
try {
  const parsed = JSON.parse(jsonString);
  console.log('✓ JSON parseado exitosamente');
  return parsed;
} catch (e1) {
  console.log('⚠ Primera intento falló:', e1.message);

  // Intento 2: Desescapar
  try {
    const unescaped = jsonString
      .replace(/\\\\"/g, '"')
      .replace(/\\\\\\\\"/g, '\\"')
      .replace(/\\\\\\\\/g, '\\');

    const parsed = JSON.parse(unescaped);
    console.log('✓ JSON parseado después de desescapar');
    return parsed;
  } catch (e2) {
    console.log('❌ Segundo intento también falló:', e2.message);
    console.log('=== CONTENIDO COMPLETO ===');
    console.log(jsonString);

    throw new Error(`No se pudo parsear. Error 1: ${e1.message}. Error 2: ${e2.message}. Revisa los logs arriba.`);
  }
}

const crypto = require('crypto');

const accessKey = '***REMOVED-SECRET***';
const secretKey = '***REMOVED-SECRET***';
const partnerTag = 'samuelwilkie-20';
const host = 'webservices.amazon.com';
const region = 'us-east-1';

function getSignature(canonicalRequest, date, time) {
  const kDate = crypto.createHmac('sha256', 'AWS4' + secretKey).update(date).digest();
  const kRegion = crypto.createHmac('sha256', kDate).update(region).digest();
  const kService = crypto.createHmac('sha256', kRegion).update('ProductAdvertisingAPI').digest();
  const kSigning = crypto.createHmac('sha256', kService).update('aws4_request').digest();
  const stringToSign = `AWS4-HMAC-SHA256\n${time}\n${date}/${region}/ProductAdvertisingAPI/aws4_request\n${crypto.createHash('sha256').update(canonicalRequest).digest('hex')}`;
  return crypto.createHmac('sha256', kSigning).update(stringToSign).digest('hex');
}

return items.map(i => {
  const keyword = i.json.amazon_keywords || "AI business";

  const requestBody = {
    Keywords: keyword,
    PartnerTag: partnerTag,
    PartnerType: 'Associates',
    Resources: [
      'Images.Primary.Medium',
      'ItemInfo.Title',
      'Offers.Listings.Price'
    ],
    SearchIndex: 'All',
    ItemCount: 3
  };

  const bodyString = JSON.stringify(requestBody);
  const amzDate = new Date().toISOString().replace(/[:-]|\.\\d{3}/g, '');
  const dateStamp = amzDate.substring(0, 8);
  const timeStamp = amzDate;

  const canonicalHeaders = `host:${host}\nx-amz-date:${timeStamp}\nx-amz-target:com.amazon.paapi5.v1.ProductAdvertisingAPIv1.SearchItems\n`;
  const signedHeaders = 'host;x-amz-date;x-amz-target';
  const canonicalRequest = `POST\n/paapi5/searchitems\n\n${canonicalHeaders}\n${signedHeaders}\n${crypto.createHash('sha256').update(bodyString).digest('hex')}`;
  const signature = getSignature(canonicalRequest, dateStamp, timeStamp);

  i.json.url = `https://${host}/paapi5/searchitems`;
  i.json.body = requestBody;
  i.json.headers = {
    'host': host,
    'x-amz-date': timeStamp,
    'x-amz-target': 'com.amazon.paapi5.v1.ProductAdvertisingAPIv1.SearchItems',
    'Content-Type': 'application/json; charset=utf-8',
    'X-Amz-Content-Sha256': crypto.createHash('sha256').update(bodyString).digest('hex'),
    'Authorization': `AWS4-HMAC-SHA256 Credential=${accessKey}/${dateStamp}/${region}/ProductAdvertisingAPI/aws4_request, SignedHeaders=${signedHeaders}, Signature=${signature}`
  };

  return i;
});

const searchResult = $input.item.json.SearchResult;

if (!searchResult || !searchResult.Items) {
  return [];
}

const products = searchResult.Items.map(item => {
  return {
    json: {
      asin: item.ASIN,
      title: item.ItemInfo.Title.DisplayValue,
      url: item.DetailPageURL,
      imageUrl: item.Images.Primary.Medium.URL,
      price: item.Offers?.Listings[0]?.Price?.DisplayAmount || 'No disponible'
    }
  };
});

return products;

const data = $input.first().json;

// En el nuevo sistema los tags son directamente los nombres
let tagsArray = [];
if (data.tags) {
  tagsArray = Array.isArray(data.tags) ? data.tags : data.tags.split(',').map(t => t.trim());
}

const wpBody = {
  title: data.title,
  excerpt: data.excerpt,
  content: data.content,
  status: 'published',
  category_slug: 'ia', // O mapéalo si tienes lógica de categorías
  tags: tagsArray,
  featured_image: data.imagen_destacada_url,
  meta_description: data.meta_description || data.excerpt.substring(0, 160)
};

console.log('=== BODY PARA LOOKITRY ===');
console.log('Tags:', tagsArray);
console.log('Featured Image:', wpBody.featured_image);

return {
  json: {
    wpBody: wpBody,
    ...data
  }
};

const item = $input.all()[0];
let content = item.json;

console.log('=== VALIDACIÓN DE CONTENIDO ===');
console.log('Tipo de content:', typeof content);
console.log('Tags recibidos:', content.Tags);

// Si viene como string, parsearlo
if (typeof content === 'string') {
  try {
    content = JSON.parse(content);
    console.log('✓ JSON parseado correctamente');
  } catch (e) {
    throw new Error(`Error al parsear JSON: ${e.message}\nContenido: ${content.substring(0, 200)}`);
  }
}

// CRÍTICO: Si los Tags no están en el content parseado, buscarlos en el input original
if (!content.Tags) {
  console.log('⚠ Tags no encontrados en content, buscando en input...');

  // Buscar en todos los items de input
  const allInputs = $input.all();
  for (const inputItem of allInputs) {
    if (inputItem.json.Tags) {
      content.Tags = inputItem.json.Tags;
      console.log('✓ Tags recuperados del input:', content.Tags);
      break;
    }
  }

  // Si aún no hay tags, intentar del nodo anterior
  if (!content.Tags) {
    try {
      const prevData = $('Añadir Enlace Hostinger').first().json;
      if (prevData.Tags) {
        content.Tags = prevData.Tags;
        console.log('✓ Tags recuperados de nodo anterior:', content.Tags);
      }
    } catch (e) {
      console.log('⚠ No se pudieron recuperar Tags de nodo anterior');
    }
  }
}

// Validar campos críticos
const required = ['title', 'excerpt', 'featured_media'];
const missing = [];
for (const field of required) {
  if (!content[field]) {
    missing.push(field);
  }
}
if (missing.length > 0) {
  throw new Error(`Campos requeridos faltantes: ${missing.join(', ')}`);
}

// Manejar meta_description
if (!content.meta_description || content.meta_description.trim() === '') {
  console.log('⚠ meta_description vacío, usando excerpt como fallback');
  content.meta_description = content.excerpt.substring(0, 160);
}

console.log('✓ meta_description:', content.meta_description.substring(0, 50) + '...');

// Validar longitudes
if (content.title && content.title.length > 60) {
  console.log('⚠ Título muy largo:', content.title.length, 'caracteres');
}

if (content.excerpt && content.excerpt.length > 160) {
  console.log('⚠ Excerpt muy largo:', content.excerpt.length, 'caracteres');
  content.excerpt = content.excerpt.substring(0, 157) + '...';
}

if (content.meta_description && content.meta_description.length > 160) {
  console.log('⚠ Meta description muy larga:', content.meta_description.length, 'caracteres');
  content.meta_description = content.meta_description.substring(0, 157) + '...';
}

console.log('=== VALIDACIÓN COMPLETA ===');
console.log('Tags finales que se pasarán:', content.Tags);

return {
  json: content
};

// Extrae título y url de todos los blogs en la categoría
const enlacesBlogs = items.map(item => ({
  titulo: item.json.title.rendered,
  url: item.json.link
}));

return [{
  json: { enlacesBlogs }
}];

// Obtiene TODOS los items que llegan a este nodo desde las diferentes ramas
const allItems = $input.all();

// Inicializa un objeto para consolidar toda la información
const datosFinales = {};

// --- BÚSQUEDA INTELIGENTE DE DATOS ---

// 1. Busca los datos del tema original (del nodo 'Obtener Temas')
const itemDelTema = allItems.find(item => item.json.tema && item.json.palabras);
if (itemDelTema) {
  // Copiar TODOS los campos del tema, incluyendo Tags
  Object.keys(itemDelTema.json).forEach(key => {
    datosFinales[key] = itemDelTema.json[key];
  });
  console.log('✓ Datos del tema encontrados');
  console.log('  - Tags originales:', itemDelTema.json.Tags);
  console.log('  - Tipo de Tags:', typeof itemDelTema.json.Tags);
}

// 2. Busca los datos de las imágenes ya subidas y ordenadas
const itemDeImagenes = allItems.find(item => item.json.imagen_destacada);
if (itemDeImagenes) {
  // Solo agregar campos de imágenes, NO sobrescribir Tags
  datosFinales.imagen_destacada = itemDeImagenes.json.imagen_destacada;
  datosFinales.imagen_destacada_url = itemDeImagenes.json.imagen_destacada?.url;
  datosFinales.imagen_destacada_id = itemDeImagenes.json.imagen_destacada?.id;
  datosFinales.imagen_body1 = itemDeImagenes.json.imagen_body1;
  datosFinales.imagen_body1_url = itemDeImagenes.json.imagen_body1?.url;
  datosFinales.imagen_body1_id = itemDeImagenes.json.imagen_body1?.id;
  datosFinales.imagen_body2 = itemDeImagenes.json.imagen_body2;
  datosFinales.imagen_body2_url = itemDeImagenes.json.imagen_body2?.url;
  datosFinales.imagen_body2_id = itemDeImagenes.json.imagen_body2?.id;
  console.log('✓ Datos de imágenes encontrados');
}

// 3. Busca la lista de enlaces de blogs existentes
const itemDeEnlaces = allItems.find(item => Array.isArray(item.json.enlacesBlogs));
if (itemDeEnlaces) {
  datosFinales.enlacesBlogs = itemDeEnlaces.json.enlacesBlogs;
  console.log('✓ Enlaces de blogs encontrados');
}

// 4. FORMATEA LOS TAGS: Convierte el string "93, 90, 87" a un array de números [93, 90, 87]
let tagsArray = [];
if (datosFinales.Tags) {
  if (typeof datosFinales.Tags === 'string') {
    tagsArray = datosFinales.Tags.split(',').map(t => parseInt(t.trim())).filter(t => !isNaN(t));
    console.log('✓ Tags convertidos de string a array:', tagsArray);
  } else if (Array.isArray(datosFinales.Tags)) {
    tagsArray = datosFinales.Tags;
    console.log('✓ Tags ya en formato array:', tagsArray);
  }
} else {
  console.log('⚠ No se encontraron Tags en los datos');
  console.log('Campos disponibles:', Object.keys(datosFinales));
}

datosFinales.Tags = tagsArray;

// 5. Añade el enlace de Hostinger
datosFinales.hostinger_link = "https://hostinger.co?REFERRALCODE=1SAM870";

console.log('=== DATOS FINALES CONSOLIDADOS ===');
console.log('Tags finales:', datosFinales.Tags);

// Devuelve un único item con toda la información consolidada
return [{
  json: datosFinales
}];

const imagenesUnidas = $input.first().json;
const datosOriginales = $('Obtener Temas').first().json;

console.log('=== DEBUG RECUPERAR DATOS ===');
console.log('Tags de Obtener Temas:', datosOriginales.Tags);
console.log('Tipo:', typeof datosOriginales.Tags);

return {
  json: {
    // Datos del tema original (INCLUYENDO TAGS)
    tema: datosOriginales.tema,
    palabras: datosOriginales.palabras,
    meta_descripcion: datosOriginales.Meta_descripcion,
    Tags: datosOriginales.Tags, // ← CRÍTICO: Preservar los Tags aquí

    // URLs e IDs de las imágenes consolidadas
    imagen_destacada_url: imagenesUnidas.imagen_destacada.url,
    imagen_destacada_id: imagenesUnidas.imagen_destacada.id,
    imagen_body1_url: imagenesUnidas.imagen_body1.url,
    imagen_body1_id: imagenesUnidas.imagen_body1.id,
    imagen_body2_url: imagenesUnidas.imagen_body2.url,
    imagen_body2_id: imagenesUnidas.imagen_body2.id
  }
};

const items = $input.all();

// Ordenar por orden
const ordenadas = items.sort((a, b) => a.json.orden - b.json.orden);

console.log('Imágenes recibidas:', ordenadas.map(i => i.json.tipo).join(', '));

return [{
  json: {
    imagen_destacada: {
      id: ordenadas[0].json.id,
      url: ordenadas[0].json.file_url || ordenadas[0].json.url || ordenadas[0].json.source_url
    },
    imagen_body1: {
      id: ordenadas[1].json.id,
      url: ordenadas[1].json.file_url || ordenadas[1].json.url || ordenadas[1].json.source_url
    },
    imagen_body2: {
      id: ordenadas[2].json.id,
      url: ordenadas[2].json.file_url || ordenadas[2].json.url || ordenadas[2].json.source_url
    }
  }
}];

// Extraer los 3 prompts del texto generado
const text = $input.first().json.content.parts[0].text;

// Buscar los patrones (A), (B), (C)
const promptA = text.match(/\(A\)\s*["""]([^"""]+)["""]/)?.[1] || 
                text.match(/\(A\)\s*(.+?)(?=\(B\)|$)/s)?.[1]?.trim();

const promptB = text.match(/\(B\)\s*["""]([^"""]+)["""]/)?.[1] || 
                text.match(/\(B\)\s*(.+?)(?=\(C\)|$)/s)?.[1]?.trim();

const promptC = text.match(/\(C\)\s*["""]([^"""]+)["""]/)?.[1] || 
                text.match(/\(C\)\s*(.+?)$/s)?.[1]?.trim();

// Verificar que se encontraron los 3 prompts
if (!promptA || !promptB || !promptC) {
  throw new Error(`No se pudieron extraer todos los prompts. 
    A: ${!!promptA}, B: ${!!promptB}, C: ${!!promptC}
    Texto recibido: ${text.substring(0, 500)}`);
}

return [
  {
    json: {
      prompt: promptA,
      tipo: 'destacada',
      orden: 1
    }
  },
  {
    json: {
      prompt: promptB,
      tipo: 'body1',
      orden: 2
    }
  },
  {
    json: {
      prompt: promptC,
      tipo: 'body2',
      orden: 3
    }
  }
];

// Modo: Run Once for Each Item
const item = $input.item;
const response = item.json;

// Obtener tipo y orden del nodo que dividió los items
const inputData = $('Extraer Prompts').item.json;
const tipo = inputData.tipo;
const orden = inputData.orden;

console.log(`Procesando imagen: ${tipo} (Orden: ${orden})`);

// --- INICIO DE LA VALIDACIÓN ---
// 1. Revisa si OpenRouter devolvió un error explícito.
if (response.error) {
  throw new Error(`Error de la API de OpenRouter para la imagen '${tipo}': ${response.error.message}`);
}

// 2. Usa "optional chaining" (?.) para acceder de forma segura a la URL.
// Esto evita el error "Cannot read properties of undefined".
const url = response.choices?.[0]?.message?.images?.[0]?.image_url?.url;

// 3. Verifica si la URL se encontró. Si no, la imagen no se generó.
if (!url) {
  console.log('Respuesta completa de OpenRouter:', JSON.stringify(response, null, 2));
  throw new Error(`No se encontró la URL de la imagen para '${tipo}'. La API no generó la imagen (posiblemente por el filtro de contenido). Revisa la respuesta completa en el log de arriba.`);
}
// --- FIN DE LA VALIDACIÓN ---

// Ahora que sabemos que la URL existe, la procesamos.
const base64Data = url.split('base64,')[1];

if (!base64Data) {
  throw new Error(`No se pudo extraer la data base64 de la URL para la imagen '${tipo}'.`);
}

console.log(`✓ Imagen ${tipo} extraída: ${base64Data.length} caracteres`);

return {
  json: {
    ...inputData, // Muy importante: pasar los datos originales
    base64: base64Data
  }
};

// Modo: Run Once for Each Item
const item = $input.item;
const itemIndex = $itemIndex;

console.log('=== DEBUG RENOMBRAR ===');
console.log('Item Index:', itemIndex);

let tipo, orden;

// Intentar recuperar datos del flujo de OpenRouter (arriba)
try {
  const datosOpenRouter = $('extraer imagenes').all()[itemIndex]?.json;
  if (datosOpenRouter?.tipo) {
    tipo = datosOpenRouter.tipo;
    orden = datosOpenRouter.orden;
    console.log('✓ Datos recuperados de "extraer imagenes"');
  }
} catch (e) {
  console.log('⚠ Nodo "extraer imagenes" no ejecutado');
}

// Si no hay datos del flujo superior, recuperar de "Extraer Prompts" (flujo directo)
if (!tipo) {
  try {
    const datosExtraer = $('Extraer Prompts').all()[itemIndex]?.json;
    if (datosExtraer?.tipo) {
      tipo = datosExtraer.tipo;
      orden = datosExtraer.orden;
      console.log('✓ Datos recuperados de "Extraer Prompts"');
    }
  } catch (e) {
    console.log('⚠ No se pudo recuperar de "Extraer Prompts"');
  }
}

// Si aún no hay tipo, usar el del item actual o fallback
if (!tipo) {
  tipo = item.json.tipo || 'imagen';
  orden = item.json.orden || itemIndex + 1;
  console.log('⚠ Usando datos del item actual o fallback');
}

console.log('Tipo final:', tipo);
console.log('Orden final:', orden);
console.log('Tiene binary.data?:', !!item.binary?.data);

// Renombrar el archivo binario con la extensión .webp
if (item.binary && item.binary.data) {
  const nuevoNombre = `${tipo}.webp`;
  item.binary.data.fileName = nuevoNombre;
  item.binary.data.mimeType = 'image/webp';

  console.log(`✓ Renombrado a: ${nuevoNombre}`);
}

// IMPORTANTE: Restaurar también los datos JSON para los nodos siguientes
return {
  json: {
    ...item.json,
    tipo: tipo,
    orden: orden
  },
  binary: item.binary
};
